import{_ as t,o as a,c as l,ag as n}from"./chunks/framework.BDReElpY.js";const y=JSON.parse('{"title":"Type System","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/types.md","filePath":"archive/reference/types.md"}'),i={name:"archive/reference/types.md"};function s(o,e,r,d,c,p){return a(),l("div",null,[...e[0]||(e[0]=[n(`<h1 id="type-system" tabindex="-1">Type System <a class="header-anchor" href="#type-system" aria-label="Permalink to &quot;Type System&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>Vex features a static, strong, and structural type system with rich compile-time metaprogramming capabilities.</p><hr><h2 id="_1-primitive-types" tabindex="-1">1. Primitive Types <a class="header-anchor" href="#_1-primitive-types" aria-label="Permalink to &quot;1. Primitive Types&quot;">​</a></h2><h3 id="integers" tabindex="-1">Integers <a class="header-anchor" href="#integers" aria-label="Permalink to &quot;Integers&quot;">​</a></h3><p>Fixed-size signed and unsigned integers.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Bits</th><th style="text-align:left;">Range</th></tr></thead><tbody><tr><td style="text-align:left;"><code>i8</code>, <code>u8</code></td><td style="text-align:left;">8</td><td style="text-align:left;">-128..127 / 0..255</td></tr><tr><td style="text-align:left;"><code>i16</code>, <code>u16</code></td><td style="text-align:left;">16</td><td style="text-align:left;">Small counters</td></tr><tr><td style="text-align:left;"><code>i32</code>, <code>u32</code></td><td style="text-align:left;">32</td><td style="text-align:left;"><strong>Default</strong>. Standard arithmetic.</td></tr><tr><td style="text-align:left;"><code>i64</code>, <code>u64</code></td><td style="text-align:left;">64</td><td style="text-align:left;">Pointers/Sizes on 64-bit systems.</td></tr><tr><td style="text-align:left;"><code>i128</code>, <code>u128</code></td><td style="text-align:left;">128</td><td style="text-align:left;">High-precision/Crypto.</td></tr></tbody></table><h3 id="floating-point" tabindex="-1">Floating Point <a class="header-anchor" href="#floating-point" aria-label="Permalink to &quot;Floating Point&quot;">​</a></h3><p>IEEE 754 floats.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Bits</th><th style="text-align:left;">Precision</th></tr></thead><tbody><tr><td style="text-align:left;"><code>f16</code></td><td style="text-align:left;">16</td><td style="text-align:left;">Machine learning / Graphics</td></tr><tr><td style="text-align:left;"><code>f32</code></td><td style="text-align:left;">32</td><td style="text-align:left;">Standard graphics</td></tr><tr><td style="text-align:left;"><code>f64</code></td><td style="text-align:left;">64</td><td style="text-align:left;"><strong>Default</strong>. High precision physics/math.</td></tr></tbody></table><h3 id="boolean" tabindex="-1">Boolean <a class="header-anchor" href="#boolean" aria-label="Permalink to &quot;Boolean&quot;">​</a></h3><p><code>bool</code>: <code>true</code> or <code>false</code>. (1 byte).</p><h3 id="string" tabindex="-1">String <a class="header-anchor" href="#string" aria-label="Permalink to &quot;String&quot;">​</a></h3><p><code>string</code>: UTF-8 encoded, dynamic length, heap-allocated.<br> See <code>12. Strings</code> for full details.</p><h3 id="special-types" tabindex="-1">Special Types <a class="header-anchor" href="#special-types" aria-label="Permalink to &quot;Special Types&quot;">​</a></h3><ul><li><strong><code>nil</code></strong>: Unit type (void).</li><li><strong><code>never</code></strong>: The bottom type (!), representing computations that never complete.</li><li><strong><code>any</code></strong>: Dynamic type (erased).</li><li><strong><code>byte</code></strong>: Alias for <code>u8</code>.</li></ul><hr><h2 id="_2-built-in-core-types" tabindex="-1">2. Built-in Core Types <a class="header-anchor" href="#_2-built-in-core-types" aria-label="Permalink to &quot;2. Built-in Core Types&quot;">​</a></h2><p>Vex implements these types directly in the AST for zero-overhead performance.</p><h3 id="option-result-null-safety" tabindex="-1">Option &amp; Result (Null Safety) <a class="header-anchor" href="#option-result-null-safety" aria-label="Permalink to &quot;Option &amp; Result (Null Safety)&quot;">​</a></h3><p>First-class support for safety without null pointer exceptions.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Option&lt;T&gt;: Some(T) or None</span></span>
<span class="line"><span>let maybe_num: Option&lt;i32&gt; = Some(10);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Result&lt;T, E&gt;: Ok(T) or Err(E)</span></span>
<span class="line"><span>let res: Result&lt;i32, string&gt; = Ok(200);</span></span></code></pre></div><h3 id="collections-ast-implemented" tabindex="-1">Collections (AST Implemented) <a class="header-anchor" href="#collections-ast-implemented" aria-label="Permalink to &quot;Collections (AST Implemented)&quot;">​</a></h3><p>Map directly to high-performance internal structures.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Vec&lt;T&gt;</code></td><td style="text-align:left;">Growable array (Heap).</td></tr><tr><td style="text-align:left;"><code>Map&lt;K, V&gt;</code></td><td style="text-align:left;">Hash map.</td></tr><tr><td style="text-align:left;"><code>Set&lt;T&gt;</code></td><td style="text-align:left;">Hash set.</td></tr></tbody></table><h3 id="memory-concurrency" tabindex="-1">Memory &amp; Concurrency <a class="header-anchor" href="#memory-concurrency" aria-label="Permalink to &quot;Memory &amp; Concurrency&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Box&lt;T&gt;</code></td><td style="text-align:left;">Heap allocation.</td></tr><tr><td style="text-align:left;"><code>Channel&lt;T&gt;</code></td><td style="text-align:left;">MPSC Channel for <code>go</code> routines.</td></tr></tbody></table><hr><h2 id="_3-compound-types" tabindex="-1">3. Compound Types <a class="header-anchor" href="#_3-compound-types" aria-label="Permalink to &quot;3. Compound Types&quot;">​</a></h2><h3 id="arrays-slices" tabindex="-1">Arrays &amp; Slices <a class="header-anchor" href="#arrays-slices" aria-label="Permalink to &quot;Arrays &amp; Slices&quot;">​</a></h3><ul><li><strong>Array</strong>: <code>[T; N]</code> (Fixed size, stack/static).</li><li><strong>Slice</strong>: <code>&amp;[T]</code> (View into array).</li></ul><h3 id="tuples" tabindex="-1">Tuples <a class="header-anchor" href="#tuples" aria-label="Permalink to &quot;Tuples&quot;">​</a></h3><p>Heterogeneous fixed-size grouping.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let pair: (i32, string) = (1, &quot;one&quot;);</span></span></code></pre></div><h3 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h3><ul><li><code>&amp;T</code>: Immutable reference.</li><li><code>&amp;T!</code>: Mutable reference.</li></ul><hr><h2 id="_4-advanced-types" tabindex="-1">4. Advanced Types <a class="header-anchor" href="#_4-advanced-types" aria-label="Permalink to &quot;4. Advanced Types&quot;">​</a></h2><h3 id="algebraic-types" tabindex="-1">Algebraic Types <a class="header-anchor" href="#algebraic-types" aria-label="Permalink to &quot;Algebraic Types&quot;">​</a></h3><ul><li><strong>Union</strong>: <code>Type A | Type B</code> (Sum type).</li><li><strong>Intersection</strong>: <code>Type A &amp; Type B</code> (Satisfies both contracts - Planned).</li></ul><h3 id="metaprogramming-types" tabindex="-1">Metaprogramming Types <a class="header-anchor" href="#metaprogramming-types" aria-label="Permalink to &quot;Metaprogramming Types&quot;">​</a></h3><ul><li><strong>Conditional</strong>: <code>T extends U ? X : Y</code> (Planned)</li><li><strong>Typeof</strong>: <code>$typeof(expr)</code> returns the type at compile time.</li><li><strong>Infer</strong>: <code>infer T</code> for type deduction in constraints.</li></ul><hr><h2 id="_5-type-inference" tabindex="-1">5. Type Inference <a class="header-anchor" href="#_5-type-inference" aria-label="Permalink to &quot;5. Type Inference&quot;">​</a></h2><p>Vex infers types locally. Global items (functions args/return) require annotations.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 10;      // Inferred i32</span></span>
<span class="line"><span>let y = x * 2;   // Inferred i32</span></span></code></pre></div><h2 id="_6-type-hierarchy" tabindex="-1">6. Type Hierarchy <a class="header-anchor" href="#_6-type-hierarchy" aria-label="Permalink to &quot;6. Type Hierarchy&quot;">​</a></h2><p>Vex uses a structural type system for Contracts (Traits), but nominal typing for Structs/Enums.</p><ul><li><strong>Upcasting</strong>: Automatic for <code>T -&gt; Contract</code> if T implements Contract.</li><li><strong>Coercion</strong>: No implicit numeric coercion.</li></ul>`,50)])])}const g=t(i,[["render",s]]);export{y as __pageData,g as default};
